You're looking for a cache that persists separately for each index file, so that when old index files are removed, the corresponding cache is also removed. This is a common requirement in scenarios where data is periodically purged.

Here's an example of how you can implement this using Python and the `lru-cache` library:

```python
import os
from functools import lru_cache

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir

    def _get_cache_file(self, index_file):
        return os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")

    @lru_cache(maxsize=None)
    def get(self, index_file, key):
        cache_file = self._get_cache_file(index_file)
        try:
            with open(cache_file, "r") as f:
                return eval(f.read())
        except FileNotFoundError:
            return None

    def set(self, index_file, key, value):
        cache_file = self._get_cache_file(index_file)
        with open(cache_file, "w") as f:
            f.write(repr(value))

    def delete(self, index_file, key):
        cache_file = self._get_cache_file(index_file)

